// Normalize name, calculate alcohol amount and order string for current order
const body        = $input.first().json.body;
const rawName     = (body.name || 'Anonymous').trim();
const name        = rawName.charAt(0).toUpperCase() + rawName.slice(1).toLowerCase();
const orderTime   = body.time || new Date().toLocaleString();
const items       = body.items || [];
const today       = new Date().toISOString().slice(0, 10);

const alcoholGrams = items.reduce((s, i) => s + (i.alcohol_grams || 0) * (i.quantity || 1), 0);

const orderStr = items
  .map(i => {
    let s = i.quantity + 'x ' + i.name;
    if (i.detail) s += ' ' + i.detail;
    return s;
  })
  .join(', ');

return [{ json: { name, orderTime, items, orderStr, alcoholGrams: Math.round(alcoholGrams * 10) / 10, today } }];

// Calculate cumulative BAC by reading today's rows from the DataTable
// rows = all orders for this person today (including the one just inserted)
const rows       = $input.all().map(i => i.json);
const name       = $('Calculate Alcohol and Format Order').item.json.name;
const orderTime  = $('Calculate Alcohol and Format Order').item.json.orderTime;
const orderStr   = $('Calculate Alcohol and Format Order').item.json.orderStr;

const totalAlcohol = Math.round(rows.reduce((s, r) => s + (r.alcohol_grams || 0), 0) * 10) / 10;
const orderCount   = rows.length;
const bac          = totalAlcohol > 0 ? totalAlcohol / (70 * 0.68) : 0;
const bacStr       = bac.toFixed(2);

const E_OK    = String.fromCodePoint(0x1F7E2);
const E_WARN  = String.fromCodePoint(0x1F7E1);
const E_OVER  = String.fromCodePoint(0x1F534);
const E_NONE  = String.fromCodePoint(0x2B1C);
const E_LIST  = String.fromCodePoint(0x1F4CB);
const E_CLOCK = String.fromCodePoint(0x1F552);
const E_DRINK = String.fromCodePoint(0x1F378);
const E_WATER = String.fromCodePoint(0x1F964);
const E_TIME  = String.fromCodePoint(0x1F550);

let bacLevel;
if      (bac === 0)  bacLevel = E_NONE;
else if (bac < 0.2)  bacLevel = E_OK;
else if (bac < 0.5)  bacLevel = E_WARN;
else                  bacLevel = E_OVER;

// Previous orders = all rows except the last one (just inserted)
const prevOrders = rows.slice(0, -1);
const historyStr = prevOrders.length > 0
  ? '\n' + E_LIST + ' Already ordered today (' + prevOrders.length + ' orders):\n'
    + prevOrders.map(r => '  - ' + r.item + '  ' + E_CLOCK + ' ' + r.order_time).join('\n')
  : '';

const bacRow = totalAlcohol > 0
  ? '\n' + E_DRINK + ' BAC ~' + bacStr + ' g/L  ' + bacLevel
  : '\n' + E_WATER + ' no alcohol';

const message = name + ': ' + orderStr
  + '\n' + E_TIME + ' ' + orderTime
  + historyStr
  + bacRow;

return [{
  json: {
    name,
    orderTime,
    orderStr,
    message,
    bac:          bacStr,
    bacLevel,
    totalAlcohol,
    alcoholGrams: $('Calculate Alcohol and Format Order').item.json.alcoholGrams,
    orderCount,
    today: $('Calculate Alcohol and Format Order').item.json.today
  }
}];
